namespace sv_5cc5fba365924f7a9dc1eb734511b76c.Services;

public sealed class RecipeService
{
    private static readonly Dictionary<int, List<Recipe>> RecipesByCuisine = new()
    {
        [1] = new List<Recipe>
        {
            new(1, "Margherita Pizza", "Classic Neapolitan pizza with tomato, mozzarella, and basil.", 30),
            new(2, "Risotto alla Milanese", "Creamy saffron risotto from Milan.", 45),
            new(3, "Tiramisu", "Layered coffee-flavored Italian dessert.", 40),
        },
        [2] = new List<Recipe>
        {
            new(4, "Kung Pao Chicken", "Spicy stir-fried chicken with peanuts and chili peppers.", 25),
            new(5, "Mapo Tofu", "Silken tofu in a fiery Sichuan sauce with ground pork.", 20),
            new(6, "Xiaolongbao", "Steamed soup dumplings filled with pork and broth.", 90),
        },
        [3] = new List<Recipe>
        {
            new(7, "Tacos al Pastor", "Spit-grilled pork tacos with pineapple and cilantro.", 35),
            new(8, "Guacamole", "Fresh avocado dip with lime, onion, and jalapeño.", 10),
            new(9, "Churros", "Fried dough pastry dusted with cinnamon sugar.", 50),
        },
    };

    public async Task<List<Recipe>> GetByCuisineAsync(int cuisineId, CancellationToken cancellationToken)
    {
        await Task.Delay(2000, cancellationToken);

        return RecipesByCuisine.TryGetValue(cuisineId, out var recipes)
            ? recipes
            : [];
    }
}

@page "/recipes/{CuisineId:int}"
@using sv_5cc5fba365924f7a9dc1eb734511b76c.Services
@rendermode InteractiveServer
@inject RecipeService RecipeService
@inject ILogger<Recipes> Logger
@implements IAsyncDisposable

<PageTitle>Recipes</PageTitle>

<h1>Recipes — Cuisine @CuisineId</h1>

@if (_error is not null)
{
    <div class="alert alert-danger" role="alert">
        <p>@_error</p>
        <button class="btn btn-outline-danger btn-sm" @onclick="Retry">Retry</button>
    </div>
}
else if (_recipes is null)
{
    <p><em>Loading recipes…</em></p>
}
else
{
    @if (_isRefreshing)
    {
        <p><em>Refreshing…</em></p>
    }

    @if (_recipes.Count == 0)
    {
        <p>No recipes found for this cuisine.</p>
    }
    else
    {
        <table class="table">
            <thead>
                <tr>
                    <th>Title</th>
                    <th>Description</th>
                    <th>Prep Time (min)</th>
                </tr>
            </thead>
            <tbody>
                @foreach (var recipe in DisplayedRecipes)
                {
                    <tr>
                        <td>@recipe.Title</td>
                        <td>@recipe.Description</td>
                        <td>@recipe.PrepTimeMinutes</td>
                    </tr>
                }
            </tbody>
        </table>
    }
}

@code {
    [Parameter]
    public int CuisineId { get; set; }

    [SupplyParameterFromQuery(Name = "sort")]
    public string? Sort { get; set; }

    private List<Recipe>? _recipes;
    private bool _isRefreshing;
    private string? _error;
    private int _loadedCuisineId;

    private CancellationTokenSource? _loadCts;
    private readonly CancellationTokenSource _disposeCts = new();

    private IEnumerable<Recipe> DisplayedRecipes =>
        string.Equals(Sort, "popular", StringComparison.OrdinalIgnoreCase)
            ? _recipes!.OrderByDescending(r => r.Id)
            : string.Equals(Sort, "newest", StringComparison.OrdinalIgnoreCase)
                ? _recipes!.OrderBy(r => r.Id)
                : _recipes!;

    protected override Task OnParametersSetAsync()
    {
        // Only reload data when the cuisine changes, not when sort changes.
        if (CuisineId != _loadedCuisineId)
        {
            return LoadRecipesAsync();
        }

        return Task.CompletedTask;
    }

    private async Task LoadRecipesAsync()
    {
        // Cancel any in-flight load for a previous cuisine.
        if (_loadCts is not null)
        {
            await _loadCts.CancelAsync();
            _loadCts.Dispose();
        }

        _loadCts = CancellationTokenSource.CreateLinkedTokenSource(_disposeCts.Token);
        var cts = _loadCts;

        _error = null;
        _isRefreshing = _recipes is not null;
        _loadedCuisineId = CuisineId;

        try
        {
            var results = await RecipeService.GetByCuisineAsync(CuisineId, cts.Token);

            // Guard against a cancelled load overwriting newer results.
            if (cts.Token.IsCancellationRequested)
            {
                return;
            }

            _recipes = results;
        }
        catch (OperationCanceledException) when (cts.Token.IsCancellationRequested)
        {
            // Load was intentionally cancelled — nothing to do.
            return;
        }
        catch (TimeoutException ex)
        {
            Logger.LogError(ex, "Timeout loading recipes for cuisine {CuisineId}", CuisineId);
            _error = "The request timed out. Please try again.";
        }
        catch (Exception ex)
        {
            Logger.LogError(ex, "Error loading recipes for cuisine {CuisineId}", CuisineId);
            _error = "Something went wrong while loading recipes. Please try again.";
        }
        finally
        {
            _isRefreshing = false;
        }
    }

    private Task Retry() => LoadRecipesAsync();

    public async ValueTask DisposeAsync()
    {
        await _disposeCts.CancelAsync();
        _disposeCts.Dispose();

        if (_loadCts is not null)
        {
            _loadCts.Dispose();
        }
    }
}

